const canvas = document.getElementById('gameCanvas');
const ctx = canvas.getContext('2d');

let player = {
  x: canvas.width / 2,
  y: canvas.height - 30,
  speed: 0.2, // pixels per millisecond
  width: 20,
  height: 20
};

let keys = {};

window.addEventListener('keydown', (e) => {
  keys[e.key] = true;
});

window.addEventListener('keyup', (e) => {
  keys[e.key] = false;
});

function updatePlayerPosition(deltaTime) {
  if (keys['ArrowUp']) player.y -= player.speed * deltaTime;
  if (keys['ArrowDown']) player.y += player.speed * deltaTime;
  if (keys['ArrowLeft']) player.x -= player.speed * deltaTime;
  if (keys['ArrowRight']) player.x += player.speed * deltaTime;

  // Boundary checks
  if (player.x < 0) player.x = 0;
  if (player.x + player.width > canvas.width) player.x = canvas.width - player.width;
  if (player.y < 0) player.y = 0;
  if (player.y + player.height > canvas.height) player.y = canvas.height - player.height;
}

function drawPlayer() {
  ctx.fillStyle = '#0095DD';
  ctx.fillRect(player.x, player.y, player.width, player.height);
}

let lastTime = performance.now();

function gameLoop() {
  const currentTime = performance.now();
  const deltaTime = currentTime - lastTime;
  lastTime = currentTime;

  ctx.clearRect(0, 0, canvas.width, canvas.height);
  updatePlayerPosition(deltaTime);
  drawPlayer();

  requestAnimationFrame(gameLoop);
}

gameLoop();